#if canImport(AppKit)
import AppKit

/// The Lumos wand-and-bloom mark, embedded as a base64 PNG so it renders
/// identically whether the app runs from the raw dev binary (`.build/debug/lumos`)
/// or the assembled `.app` — neither `Bundle.main` resource lookup nor
/// SVG-in-NSImage is reliable across both, so the bytes travel in the binary.
enum OnboardingMark {
    static func image() -> NSImage? {
        guard let data = Data(base64Encoded: base64PNG, options: .ignoreUnknownCharacters),
              let image = NSImage(data: data) else { return nil }
        return image
    }

    private static let base64PNG =
        ""
}
#endif
